// ──────────────────────────────────────────────────────────────────────
// Helpers
// ──────────────────────────────────────────────────────────────────────

func coherenceCardBorder(severity string) string {
	switch severity {
	case "critical":
		return "border-error/25"
	case "warning":
		return "border-warning/20"
	default:
		return "border-base-content/10"
	}
}

func coherenceSeverityStripe(severity string) string {
	switch severity {
	case "critical":
		return "bg-error"
	case "warning":
		return "bg-warning"
	default:
		return "bg-info"
	}
}

func equilibriumBorderClass(score float64) string {
	if score >= 0.7 {
		return "bg-success/5 border-success/20"
	}
	if score >= 0.5 {
		return "bg-warning/5 border-warning/20"
	}
	return "bg-error/5 border-error/20"
}

func equilibriumTextClass(score float64) string {
	if score >= 0.7 {
		return "text-success"
	}
	if score >= 0.5 {
		return "text-warning"
	}
	return "text-error"
}

func formatPercent(score float64) string {
	return strconv.Itoa(int(score*100)) + "%"
}

func authorityTierBadge(tier string) string {
	switch tier {
	case "autonomous":
		return "badge-success badge-outline"
	case "gated":
		return "badge-warning badge-outline"
	case "escalated":
		return "badge-error badge-outline"
	default:
		return "badge-ghost"
	}
}

